    public DateTime CreatedAtUtc { get; set; }
    public DateTime? EstimatedDeliveryUtc { get; set; }
    public DateTime? ActualDeliveryUtc { get; set; }
    public string RecipientName { get; set; } = string.Empty;
    public string CustomerEmail { get; set; } = string.Empty;
    public string? Notes { get; set; }
}

public class UpdateShipmentStatusRequest
{
    public ShipmentStatus NewStatus { get; set; }
    public string? Notes { get; set; }
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<ShipmentDto>> GetAllShipmentsAsync();
    Task<List<ShipmentDto>> GetMyShipmentsAsync();
    Task<ShipmentDto?> GetByTrackingNumberAsync(string trackingNumber);
    Task<ShipmentDto?> UpdateStatusAsync(int id, UpdateShipmentStatusRequest request);
}

public class ShipmentApiService(HttpClient http) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments") ?? [];
    }

    public async Task<List<ShipmentDto>> GetMyShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments/mine") ?? [];
    }

    public async Task<ShipmentDto?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto?> UpdateStatusAsync(int id, UpdateShipmentStatusRequest request)
    {
        var response = await http.PutAsJsonAsync($"api/shipments/{id}/status", request);
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }
}

