using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Data;

public static class SeedData
{
    public const string DispatcherRole = "Dispatcher";
    public const string CustomerRole = "Customer";

    public static async Task InitializeAsync(IServiceProvider services)
    {
        using var scope = services.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
        await db.Database.MigrateAsync();

        var roleManager = scope.ServiceProvider.GetRequiredService<RoleManager<IdentityRole>>();
        foreach (var role in new[] { DispatcherRole, CustomerRole })
        {
            if (!await roleManager.RoleExistsAsync(role))
                await roleManager.CreateAsync(new IdentityRole(role));
        }

        var userManager = scope.ServiceProvider.GetRequiredService<UserManager<ApplicationUser>>();

        var dispatcher = await EnsureUser(userManager, "dispatcher@shiptrack.io", "Dispatch1!", DispatcherRole);
        var customer1 = await EnsureUser(userManager, "alice@example.com", "Customer1!", CustomerRole);
        var customer2 = await EnsureUser(userManager, "bob@example.com", "Customer1!", CustomerRole);

        if (!await db.Shipments.AnyAsync())
        {
            var now = DateTime.UtcNow;
            db.Shipments.AddRange(
                new Shipment
                {
                    TrackingNumber = "TRK-1001",
                    Origin = "New York, NY",
                    Destination = "Los Angeles, CA",
                    Status = ShipmentStatus.InTransit,
                    CreatedAtUtc = now.AddDays(-3),
                    EstimatedDeliveryUtc = now.AddDays(2),
                    RecipientName = "Alice Johnson",
                    CustomerUserId = customer1.Id
                },
                new Shipment
                {
                    TrackingNumber = "TRK-1002",
                    Origin = "Chicago, IL",
                    Destination = "Miami, FL",
                    Status = ShipmentStatus.Pending,
                    CreatedAtUtc = now.AddDays(-1),
                    EstimatedDeliveryUtc = now.AddDays(5),
                    RecipientName = "Alice Johnson",
                    CustomerUserId = customer1.Id
                },
                new Shipment
                {
                    TrackingNumber = "TRK-1003",
                    Origin = "Seattle, WA",
                    Destination = "Denver, CO",
                    Status = ShipmentStatus.Delivered,
                    CreatedAtUtc = now.AddDays(-7),
                    EstimatedDeliveryUtc = now.AddDays(-2),
                    ActualDeliveryUtc = now.AddDays(-2).AddHours(3),
                    RecipientName = "Bob Smith",
                    CustomerUserId = customer2.Id
                },
                new Shipment
                {
                    TrackingNumber = "TRK-1004",
                    Origin = "Dallas, TX",
                    Destination = "Phoenix, AZ",
                    Status = ShipmentStatus.OutForDelivery,
                    CreatedAtUtc = now.AddDays(-4),
                    EstimatedDeliveryUtc = now,
                    RecipientName = "Bob Smith",
                    CustomerUserId = customer2.Id
                },
                new Shipment
                {
                    TrackingNumber = "TRK-1005",
                    Origin = "Boston, MA",
                    Destination = "Atlanta, GA",
                    Status = ShipmentStatus.PickedUp,
                    CreatedAtUtc = now.AddHours(-6),
                    EstimatedDeliveryUtc = now.AddDays(3),
                    RecipientName = "Alice Johnson",
                    CustomerUserId = customer1.Id
                }
            );
            await db.SaveChangesAsync();
        }
    }

    private static async Task<ApplicationUser> EnsureUser(
        UserManager<ApplicationUser> userManager, string email, string password, string role)
    {
        var user = await userManager.FindByEmailAsync(email);
        if (user is null)
        {
            user = new ApplicationUser { UserName = email, Email = email, EmailConfirmed = true };
            var result = await userManager.CreateAsync(user, password);
            if (!result.Succeeded)
                throw new Exception($"Failed to create user {email}: {string.Join(", ", result.Errors.Select(e => e.Description))}");
        }

        if (!await userManager.IsInRoleAsync(user, role))
            await userManager.AddToRoleAsync(user, role);

        return user;
    }
}

