                .Include(s => s.CustomerUser)
                .OrderByDescending(s => s.CreatedAtUtc)
                .ToListAsync();
            return shipments.Select(s => s.ToDto());
        }).RequireAuthorization(p => p.RequireRole(SeedData.DispatcherRole));

        // Current customer's shipments
        group.MapGet("/mine", async (ClaimsPrincipal user, ApplicationDbContext db) =>
        {
            var userId = user.FindFirstValue(ClaimTypes.NameIdentifier);
            var shipments = await db.Shipments
                .Include(s => s.CustomerUser)
                .Where(s => s.CustomerUserId == userId)
                .OrderByDescending(s => s.CreatedAtUtc)
                .ToListAsync();
            return shipments.Select(s => s.ToDto());
        });

        // Track by tracking number — any authenticated user
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .Include(s => s.CustomerUser)
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment.ToDto());
        });

        // Update status — dispatchers only
        group.MapPut("/{id:int}/status", async (
            int id,
            [FromBody] UpdateShipmentStatusRequest request,
            ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .Include(s => s.CustomerUser)
                .FirstOrDefaultAsync(s => s.Id == id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = request.NewStatus;
            shipment.Notes = request.Notes;
            if (request.NewStatus == ShipmentStatus.Delivered)
                shipment.ActualDeliveryUtc = DateTime.UtcNow;

            await db.SaveChangesAsync();
            return Results.Ok(shipment.ToDto());
        }).RequireAuthorization(p => p.RequireRole(SeedData.DispatcherRole));
    }
}

