@page "/dispatch"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize(Roles = "Dispatcher")]
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>📦 Dispatcher Dashboard</h2>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <div class="mb-3">
        <input class="form-control" type="text" placeholder="Filter by tracking #, destination, or status..."
               @bind="filterText" @bind:event="oninput" />
    </div>

    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Customer</th>
                    <th>Status</th>
                    <th>Est. Delivery (UTC)</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><strong>@s.TrackingNumber</strong></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td>@s.CustomerEmail</td>
                        <td><span class="badge @StatusBadgeClass(s.Status)">@s.Status</span></td>
                        <td>@s.EstimatedDeliveryUtc?.ToString("yyyy-MM-dd HH:mm")</td>
                        <td>
                            @if (s.Status != ShipmentStatus.Delivered && s.Status != ShipmentStatus.Cancelled)
                            {
                                <select class="form-select form-select-sm d-inline-block w-auto"
                                        @onchange="e => UpdateStatus(s, e)">
                                    <option value="">— Change —</option>
                                    @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                    {
                                        if (status != s.Status)
                                        {
                                            <option value="@status">@status</option>
                                        }
                                    }
                                </select>
                            }
                            else
                            {
                                <span class="text-muted">—</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    @if (updateMessage is not null)
    {
        <div class="alert @(updateSuccess ? "alert-success" : "alert-danger") mt-2" role="alert">
            @updateMessage
        </div>
    }
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private string? updateMessage;
    private bool updateSuccess;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrWhiteSpace(filterText) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Status.ToString().Contains(filterText, StringComparison.OrdinalIgnoreCase)
        ) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (e.Value is not string val || !Enum.TryParse<ShipmentStatus>(val, out var newStatus))
            return;

        var result = await ShipmentService.UpdateStatusAsync(shipment.Id, new UpdateShipmentStatusRequest
        {
            NewStatus = newStatus
        });

        if (result is not null)
        {
            var idx = shipments!.FindIndex(s => s.Id == shipment.Id);
            if (idx >= 0) shipments[idx] = result;
            updateMessage = $"Shipment {shipment.TrackingNumber} updated to {newStatus}.";
            updateSuccess = true;
        }
        else
        {
            updateMessage = $"Failed to update {shipment.TrackingNumber}.";
            updateSuccess = false;
        }
    }

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/my-shipments"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>My Shipments</PageTitle>

<h2>📬 My Shipments</h2>

@if (shipments is null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <div class="alert alert-info">You have no shipments yet.</div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4">
        @foreach (var s in shipments)
        {
            <div class="col">
                <div class="card h-100 @CardBorderClass(s.Status)">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@s.TrackingNumber</strong>
                        <span class="badge @StatusBadgeClass(s.Status)">@s.Status</span>
                    </div>
                    <div class="card-body">
                        <p class="card-text">
                            <strong>From:</strong> @s.Origin<br />
                            <strong>To:</strong> @s.Destination<br />
                            <strong>Recipient:</strong> @s.RecipientName
                        </p>
                        <p class="card-text">
                            <strong>Estimated Delivery:</strong>
                            @if (s.EstimatedDeliveryUtc.HasValue)
                            {
                                @s.EstimatedDeliveryUtc.Value.ToString("dddd, MMMM d, yyyy 'at' HH:mm UTC")
                            }
                            else
                            {
                                <span class="text-muted">TBD</span>
                            }
                        </p>
                        @if (s.ActualDeliveryUtc.HasValue)
                        {
                            <p class="card-text text-success">
                                <strong>Delivered:</strong> @s.ActualDeliveryUtc.Value.ToString("dddd, MMMM d, yyyy 'at' HH:mm UTC")
                            </p>
                        }
                        @if (!string.IsNullOrWhiteSpace(s.Notes))
                        {
                            <p class="card-text"><small class="text-muted">Notes: @s.Notes</small></p>
                        }
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<ShipmentDto>? shipments;

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetMyShipmentsAsync();
    }

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static string CardBorderClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "border-success",
        ShipmentStatus.Cancelled => "border-danger",
        ShipmentStatus.OutForDelivery => "border-warning",
        _ => ""
    };
}

@page "/track"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2>🔍 Track a Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" type="text" placeholder="Enter tracking number (e.g. TRK-1001)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@searching">
                @if (searching)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (searched && result is null)
{
    <div class="alert alert-warning">
        No shipment found for tracking number <strong>@searchedNumber</strong>.
    </div>
}
else if (result is not null)
{
    <div class="card @CardBorderClass(result.Status)" style="max-width: 600px;">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@result.TrackingNumber</strong>
            <span class="badge @StatusBadgeClass(result.Status)">@result.Status</span>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-5">Origin</dt>
                <dd class="col-sm-7">@result.Origin</dd>

                <dt class="col-sm-5">Destination</dt>
                <dd class="col-sm-7">@result.Destination</dd>

                <dt class="col-sm-5">Recipient</dt>
                <dd class="col-sm-7">@result.RecipientName</dd>

                <dt class="col-sm-5">Shipped</dt>
                <dd class="col-sm-7">@result.CreatedAtUtc.ToString("yyyy-MM-dd HH:mm") UTC</dd>

                <dt class="col-sm-5">Est. Delivery</dt>
                <dd class="col-sm-7">
                    @(result.EstimatedDeliveryUtc?.ToString("yyyy-MM-dd HH:mm") ?? "TBD") UTC
                </dd>

                @if (result.ActualDeliveryUtc.HasValue)
                {
                    <dt class="col-sm-5 text-success">Delivered</dt>
                    <dd class="col-sm-7 text-success">
                        @result.ActualDeliveryUtc.Value.ToString("yyyy-MM-dd HH:mm") UTC
                    </dd>
                }

                @if (!string.IsNullOrWhiteSpace(result.Notes))
                {
                    <dt class="col-sm-5">Notes</dt>
                    <dd class="col-sm-7">@result.Notes</dd>
                }
            </dl>
        </div>

        @{
            var steps = GetProgressSteps(result.Status);
        }
        <div class="card-footer">
            <div class="d-flex justify-content-between">
                @foreach (var (label, active) in steps)
                {
                    <div class="text-center">
                        <div class="@(active ? "text-primary fw-bold" : "text-muted")">
                            @(active ? "●" : "○")
                        </div>
                        <small class="@(active ? "fw-bold" : "text-muted")">@label</small>
                    </div>
                }
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private ShipmentDto? result;
    private bool searched;
    private bool searching;

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;
        searching = true;
        searchedNumber = trackingNumber.Trim();
        result = await ShipmentService.GetByTrackingNumberAsync(searchedNumber);
        searched = true;
        searching = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await Search();
    }

    private static List<(string Label, bool Active)> GetProgressSteps(ShipmentStatus status)
    {
        if (status == ShipmentStatus.Cancelled)
            return [("Cancelled", true)];

        var all = new[] { ShipmentStatus.Pending, ShipmentStatus.PickedUp, ShipmentStatus.InTransit, ShipmentStatus.OutForDelivery, ShipmentStatus.Delivered };
        return all.Select(s => (s.ToString(), s <= status)).ToList();
    }

    private static string StatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static string CardBorderClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "border-success",
        ShipmentStatus.Cancelled => "border-danger",
        _ => ""
    };
}

